import { useDispatch, useSelector } from 'react-redux';
import { setCategory } from '../store/slices/filtersSlice';

const CategoryFilter = ({ categories }) => {
  const dispatch = useDispatch();
  const selectedCategory = useSelector(state => state.filters.selectedCategory);

  const categoryLabels = {
    'all': 'All Products',
    'electronics': 'Electronics',
    "men's clothing": "Men's Clothing",
    "women's clothing": "Women's Clothing",
    'jewelery': 'Jewelry'
  };

  const allCategories = ['all', ...categories];

  return (
    <div className="mb-12">
      <div className="flex flex-wrap gap-4 justify-center">
        {allCategories.map((category) => (
          <button
            key={category}
            onClick={() => dispatch(setCategory(category))}
            className={`px-6 py-3 font-semibold rounded-none tracking-wide transition-all uppercase text-sm ${
              selectedCategory === category
                ? 'bg-[#F97316] text-white'
                : 'bg-transparent text-[#A3A3A3] border border-white/20 hover:border-white/50 hover:text-white'
            }`}
            data-testid={`category-filter-${category}`}
          >
            {categoryLabels[category] || category}
          </button>
        ))}
      </div>
    </div>
  );
};

export default CategoryFilter;
